class Student:
    def __init__(self, name, grades=None):
        self.name = name
        self.grades = grades or []

    def average(self):
        if not self.grades:
            return 0.0
        return sum(self.grades) / len(self.grades)

    def highest(self):
        return max(self.grades) if self.grades else 0

    def __repr__(self):
        return f"Student({self.name}, avg={self.average():.1f})"

