            print(f"Can't go {direction}.")
            return
        self.player.position = room["exits"][direction]
        print(f"-> Moved {direction}.")

    def pickup(self):
        room = self.world.get_room(self.player.position)
        if not room or not room["items"]:
            print("Nothing to pick up here.")
            return
        item = room["items"][0]
