typedef struct Node {
    int data;
    struct Node *next;
} Node;

typedef struct {
    Node *head;
    int size;
} List;

List *list_create(void);
void list_push(List *l, int value);
int  list_pop(List *l);
int  list_size(List *l);
void list_print(List *l);
void list_free(List *l);

#endif

#include <stdio.h>
#include <stdlib.h>
#include "list.h"

List *list_create(void) {
    List *l = malloc(sizeof(List));
    l->head = NULL;
    l->size = 0;
    return l;
}

void list_push(List *l, int value) {
    Node *node = malloc(sizeof(Node));
    node->data = value;
    node->next = l->head;
    l->head = node;
    l->size++;
}

int list_pop(List *l) {
    if (!l->head) return -1;
    Node *top = l->head;
    int value = top->data;
    l->head = top->next;
    free(top);
    l->size--;
    return value;
}

int list_size(List *l) {
    return l->size;
}

void list_print(List *l) {
    Node *cur = l->head;
    while (cur) {
        printf("%d ", cur->data);
        cur = cur->next;
    }
    printf("\n");
}

void list_free(List *l) {
    Node *cur = l->head;
    while (cur) {
        Node *tmp = cur;
        cur = cur->next;
        free(tmp);
    }
    free(l);
}

