class Character {
protected:
    std::string name_;
    int hp_;
    int maxHp_;
    int attack_;

public:
    Character(const std::string& name, int hp, int attack)
        : name_(name), hp_(hp), maxHp_(hp), attack_(attack) {}

    virtual ~Character() = default;

    virtual int dealDamage() const { return attack_; }
    virtual std::string className() const = 0;

    void takeDamage(int dmg) {
        hp_ -= dmg;
        if (hp_ < 0) hp_ = 0;
    }

    bool isAlive() const { return hp_ > 0; }
    const std::string& name() const { return name_; }
    int hp() const { return hp_; }

    void describe() const {
        std::cout << className() << " " << name_
                  << " [HP: " << hp_ << "/" << maxHp_
                  << ", ATK: " << attack_ << "]" << std::endl;
    }
};

#endif

