#include "Battle.h"
#include <iostream>
using namespace std;

void Battle::run() {
    int round = 1;
    while (a_.isAlive() && b_.isAlive()) {
        cout << "-- Round " << round << " --" << endl;

        int dmgA = a_.dealDamage();
        b_.takeDamage(dmgA);
        cout << "  " << a_.name() << " hits " << b_.name()
             << " for " << dmgA << " dmg (HP: " << b_.hp() << ")" << endl;

        if (!b_.isAlive()) break;

        int dmgB = b_.dealDamage();
        a_.takeDamage(dmgB);
        cout << "  " << b_.name() << " hits " << a_.name()
             << " for " << dmgB << " dmg (HP: " << a_.hp() << ")" << endl;

        round++;
    }

    cout << endl;
    if (a_.isAlive()) {
        cout << a_.name() << " wins!" << endl;
    } else {
        cout << b_.name() << " wins!" << endl;
    }
}

