/**
 * Simple in-memory Todo store.
 */
class TodoStore {
  constructor() {
    this._todos = [];
    this._nextId = 1;
  }

  add(title) {
    const todo = { id: this._nextId++, title, done: false };
    this._todos.push(todo);
    return todo;
  }

  complete(id) {
    const todo = this._todos.find(t => t.id === id);
    if (todo) todo.done = true;
    return todo;
  }

  remove(id) {
    this._todos = this._todos.filter(t => t.id !== id);
  }

  getAll() {
    return [...this._todos];
  }
}

module.exports = TodoStore;

/**
 * Display helpers for todo items.
 */
function printAll(todos) {
  todos.forEach(t => {
    const status = t.done ? '[x]' : '[ ]';
    console.log(`  ${status} #${t.id} ${t.title}`);
  });
}

function printStats(todos) {
  const done = todos.filter(t => t.done).length;
  const pending = todos.length - done;
  console.log(`  Total: ${todos.length}  Done: ${done}  Pending: ${pending}`);
}

module.exports = { printAll, printStats };

