// Generic stack
class Stack<T> {
  private items: T[] = [];

  push(item: T): void { this.items.push(item); }
  pop(): T | undefined { return this.items.pop(); }
  peek(): T | undefined { return this.items[this.items.length - 1]; }
  get size(): number { return this.items.length; }
}

const alice = createUser('Alice', 'alice@example.com');
const bob = createUser('Bob', 'bob@example.com');
console.log('Users:', [alice, bob]);
console.log('Summaries:', [alice, bob].map(summarize));

const stack = new Stack<number>();
[10, 20, 30].forEach(n => stack.push(n));
console.log(`Stack size: ${stack.size}, top: ${stack.peek()}`);
stack.pop();
console.log(`After pop – size: ${stack.size}, top: ${stack.peek()}`);

