}

/**
 * Core calculator with typed operations.
 */
export enum Operator {
  Add = '+',
  Subtract = '-',
  Multiply = '*',
  Divide = '/',
}

export function evaluate(a: number, op: Operator, b: number): number | null {
  switch (op) {
    case Operator.Add:      return a + b;
    case Operator.Subtract:  return a - b;
    case Operator.Multiply:  return a * b;
    case Operator.Divide:    return b === 0 ? null : a / b;
  }
}

import { Operator } from './calculator';

/**
 * Pretty-print a calculation result.
 */
export function formatResult(
  a: number,
  op: Operator,
  b: number,
  result: number | null
): string {
  const expr = `${a} ${op} ${b}`;
  if (result === null) return `${expr} = ERROR (division by zero)`;
  return `${expr} = ${result}`;
}

