package main

import "fmt"

// User represents a system user.
type User struct {
	Name string
	Role string
}

// Greet returns a formatted greeting for the user.
func (u User) Greet() string {
	return fmt.Sprintf("%s (%s)", u.Name, u.Role)
}

// countByRole counts users with a given role.
func countByRole(users []User, role string) int {
	count := 0
	for _, u := range users {
		if u.Role == role {
			count++
		}
	}
	return count
}

# A shopping cart that holds products with quantities.
class Cart
  def initialize
    @items = []
  end

  def add(product, qty = 1)
    existing = @items.find { |i| i[:product].name == product.name }
    if existing
      existing[:qty] += qty
    else
      @items << { product: product, qty: qty }
    end
  end

  def total
    @items.sum { |i| i[:product].price * i[:qty] }
  end

  def item_count
    @items.sum { |i| i[:qty] }
  end

  def display
    @items.each do |i|
      line_total = i[:product].price * i[:qty]
      puts "  #{i[:product].name} x#{i[:qty]}  $#{'%.2f' % line_total}"
    end
  end
end
